'use strict';

var $TypeError = require('es-errors/type');
var isNegativeZero = require('math-intrinsics/isNegativeZero');
var MAX_SAFE_INTEGER = require('math-intrinsics/constants/maxSafeInteger');

var AddValueToKeyedGroup = require('./AddValueToKeyedGroup');
var Call = require('./Call');
var GetIterator = require('./GetIterator');
var IsCallable = require('./IsCallable');
var IteratorClose = require('./IteratorClose');
var IteratorStep = require('./IteratorStep');
var IteratorValue = require('./IteratorValue');
var RequireObjectCoercible = require('./RequireObjectCoercible');
var ThrowCompletion = require('./ThrowCompletion');
var ToPropertyKey = require('./ToPropertyKey');



module.exports = function GroupBy(items, callbackfn, keyCoercion) {
	if (keyCoercion !== 'PROPERTY' && keyCoercion !== 'ZERO') {
		throw new $TypeError('Assertion failed: `keyCoercion` must be `"PROPERTY"` or `"ZERO"`');
	}

	RequireObjectCoercible(items); 

	if (!IsCallable(callbackfn)) {
		throw new $TypeError('callbackfn must be callable'); 
	}

	var groups = []; 

	var iteratorRecord = GetIterator(items, 'SYNC'); 

	var k = 0; 

	while (true) { 
		if (k >= MAX_SAFE_INTEGER) { 
			var error = ThrowCompletion(new $TypeError('k must be less than 2 ** 53 - 1')); 
			return void IteratorClose(iteratorRecord, error); 
		}
		var next = IteratorStep(iteratorRecord); 
		if (!next) { 
			return groups; 
		}

		var value = IteratorValue(next); 

		var key;
		try {
			key = Call(callbackfn, void undefined, [value, k]); 
		} catch (e) {
			return void IteratorClose(iteratorRecord, ThrowCompletion(e)); 
		}

		if (keyCoercion === 'PROPERTY') { 
			try {
				key = ToPropertyKey(key); 
			} catch (e) {
				return void IteratorClose(iteratorRecord, ThrowCompletion(e)); 
			}
		} else { 
			if (keyCoercion !== 'ZERO') {
				throw new $TypeError('Assertion failed: keyCoercion must be ~PROPERTY~ or ~ZERO~'); 
			}
			if (isNegativeZero(key)) {
				key = +0; 
			}
		}

		AddValueToKeyedGroup(groups, key, value); 

		k += 1; 
	}
};
